'use strict'

/**
 * Module exports.
 * @public
 */

module.exports = rangeParser

/**
 * Parse "Range" header `str` relative to the given file `size`.
 *
 * @param {Number} size
 * @param {String} str
 * @param {Object} [options]
 * @return {Array|Number} Ranges or negative number indicating error
 * @public
 */

function rangeParser (size, str, options) {
  if (typeof str !== 'string') {
    return -2
  }

  // Set options if not provided
  options = options || {}

  var index = str.indexOf('=')

  // Return invalid if no '=' separator
  if (index === -1) {
    return -1
  }

  // Split into type and range(s)
  var type = str.substring(0, index).trim()
  var rangesStr = str.substring(index + 1).trim()

  // Return invalid if type is not 'bytes'
  if (type !== 'bytes') {
    return -1
  }

  // Return invalid if ranges string is empty
  if (rangesStr.length === 0) {
    return -1
  }

  // Handle all ranges
  var ranges = rangesStr.split(',')
  var result = []

  // Return invalid if size is invalid
  if (isNaN(size) || !isFinite(size) || size < 0) {
    return -2
  }

  // Parse all ranges
  for (var i = 0; i < ranges.length; i++) {
    var range = ranges[i].trim()

    // Return invalid if range is empty
    if (range.length === 0) {
      return -1
    }

    // Parse range
    var parts = range.split('-')

    // Return invalid if format is invalid
    if (parts.length !== 2) {
      return -1
    }

    // Parse start and end
    var start = parts[0].trim()
    var end = parts[1].trim()

    // Return invalid if both start and end are empty
    if (start.length === 0 && end.length === 0) {
      return -1
    }

    // Parse start
    if (start.length === 0) {
      // If no start specified, end is relative to end of file
      // e.g., -500 means last 500 bytes
      start = size - parseInt(end, 10)
      end = size - 1

      // Return invalid if end is invalid
      if (isNaN(start) || !isFinite(start)) {
        return -1
      }
    } else if (end.length === 0) {
      // If no end specified, end is the end of the file
      // e.g., 500- means bytes 500 through the end
      start = parseInt(start, 10)
      end = size - 1

      // Return invalid if start is invalid
      if (isNaN(start) || !isFinite(start)) {
        return -1
      }
    } else {
      // Both start and end specified
      // e.g., 500-999 means bytes 500-999 inclusive
      start = parseInt(start, 10)
      end = parseInt(end, 10)

      // Return invalid if start or end is invalid
      if (isNaN(start) || !isFinite(start) || isNaN(end) || !isFinite(end)) {
        return -1
      }
    }

    // Return invalid if start is greater than end
    if (start > end) {
      return -1
    }

    // Return invalid if start is greater than file size
    if (start >= size) {
      // Return 416 Requested Range Not Satisfiable if all ranges are invalid
      if (options.combine !== true && i === 0) {
        return -3
      }

      // Skip this range
      continue
    }

    // Limit end to file size - 1
    if (end >= size) {
      end = size - 1
    }

    // Add range
    result.push({
      start: start,
      end: end
    })
  }

  // Return ranges or invalid
  return result.length > 0 ? result : -1
}